            + (0.05 * config.num_layers)
            - (0.1 * abs(config.learning_rate - 0.01))
            - (0.01 * (config.batch_size / 32.0)),
        ),
    )
    loss = 1.0 - accuracy
    return ExperimentResult(config=config, accuracy=accuracy, loss=loss)


